# Generate a basic pip configuration file (pip.conf) with the following settings:
# - Index-url points to internal PyPI mirror 
# - Trusted-host specifies trusted host name(s) in our case localhost

import configparser

config = configparser.ConfigParser()

# Add section
config.add_section('global')

# Set options
config.set('global', 'index-url', 'http://my.internal.pypi/simple/')
config.set('global', 'trusted-host', 'my.internal.pypi')

# Write to file
with open('pip.conf', 'w') as config_file:
    config.write(config_file)